function main({ httpResponse }) {
  const data = httpResponse?.data || [];
  // 计算总条数
  let totalCount = 0;
  data.forEach(item => {
    const dataList = item.dataList || [];
    totalCount += dataList.length;
  });
  let tokens = 0;
  if (totalCount > 0) {
    // 计算Token（字符数转K）
    const dataJsonString = JSON.stringify(data);
    tokens = Math.ceil(dataJsonString.length / 1000);
  }
  return {
    totalCount: totalCount,
    tokens: tokens
  };
}

