function main({ chartConfigResult }) {
  // 1. 校验输入
  if (!chartConfigResult) {
    return {
      success: false,
      message: "图表配置生成失败，请重试"
    };
  }

  // 2. 解析配置（处理 markdown 代码块）
  let config;
  try {
    let raw = typeof chartConfigResult === 'string' 
      ? chartConfigResult 
      : JSON.stringify(chartConfigResult);

    // 移除 markdown json 代码块标记
    raw = raw.replace(/```json\n/g, '');
    raw = raw.replace(/```\n?/g, '');
    raw = raw.trim();

    config = JSON.parse(raw);
  } catch (e) {
    return {
      success: false,
      message: "图表配置格式错误，请重新描述需求"
    };
  }

  // 3. 提取 chartConfig（兼容两种格式）
  let chartConfig;
  let dataPoints = 0;
  let originalPoints = 0;
  let isSampled = false;

  // 格式1：有 chartConfig 包装
  if (config.chartConfig) {
    chartConfig = config.chartConfig;
    dataPoints = config.dataPoints || 0;
    originalPoints = config.originalPoints || dataPoints;
    isSampled = config.isSampled || false;
  } 
  // 格式2：直接就是 chartConfig（你的情况）
  else if (config.type && config.data) {
    chartConfig = config;
    dataPoints = config.data?.labels?.length || 0;
    originalPoints = dataPoints;
    isSampled = false;
  } 
  // 格式3：检查错误
  else if (config.error) {
    return {
      success: false,
      message: config.error
    };
  }
  else {
    return {
      success: false,
      message: "图表配置不完整，请重新描述需求"
    };
  }

  // 4. 校验必要字段
  if (!chartConfig.type || !chartConfig.data || !chartConfig.data.labels || !chartConfig.data.datasets) {
    return {
      success: false,
      message: "图表配置结构错误，请重新描述需求"
    };
  }

  // 5. 校验数据不为空
  if (chartConfig.data.labels.length === 0 || chartConfig.data.datasets[0].data.length === 0) {
    return {
      success: false,
      message: "无数据可生成图表，请调整查询条件"
    };
  }

  // 6. 生成 QuickChart URL
  const encodedConfig = encodeURIComponent(JSON.stringify(chartConfig));
  const imageUrl = `https://quickchart.io/chart?c=${encodedConfig}&width=800&height=400`;

  // 7. 获取标题
  let chartTitle = "图表";
  if (chartConfig.options?.title?.text) {
    chartTitle = chartConfig.options.title.text;
  }

  // 8. 构建回复内容
  let replyContent = `根据您的要求，已生成图表：\n\n`;
  replyContent += `![${chartTitle}](${imageUrl})\n\n`;
  replyContent += `📊 图表信息：\n`;
  replyContent += `- 图表：${chartTitle}\n`;
  replyContent += `- 数据点：${dataPoints}个\n`;

  if (isSampled) {
    replyContent += `- ⚠️ 注意：原始数据共${originalPoints}条，已采样展示\n`;
  }

  // 9. 返回结果
  return {
    replyContent: replyContent
  };
}

