function main({ aiOutput }) {
  // 辅助函数：返回 error 输出
  function getErrorOutput() {
    return {
      startTime: '',
      endTime: '',
      dataEnum: '',
      dataEnumDesc: '',
      domain: 'error',
      entName: '',
      outPutName: '',
      alarmType: null,
      alarmStatus: null,
      dealStatus: null,
      outPutType: null
    };
  }

  // 检查 aiOutput 是否有效
  if (!aiOutput || aiOutput === 'null' || aiOutput === null || aiOutput === undefined) {
    return getErrorOutput();
  }

  // 解析 JSON
  let output;
  if (typeof aiOutput === 'string') {
    // 去除可能的空白字符和代码块标记
    let cleanStr = aiOutput.trim();
    // 移除可能的 ```json 和 ``` 标记
    if (cleanStr.startsWith('```json')) {
      cleanStr = cleanStr.replace(/```json\n?/, '').replace(/```$/, '');
    } else if (cleanStr.startsWith('```')) {
      cleanStr = cleanStr.replace(/```\n?/, '').replace(/```$/, '');
    }

    try {
      output = JSON.parse(cleanStr);
    } catch (e) {
      return getErrorOutput();
    }
  } else if (typeof aiOutput === 'object' && aiOutput !== null) {
    output = aiOutput;
  } else {
    return getErrorOutput();
  }

  // 验证 domain 字段是否存在
  if (!output.hasOwnProperty('domain')) {
    return getErrorOutput();
  }

  // 验证 domain 是否为有效值
  const validDomains = ['enterprise', 'outlet', 'monitoring', 'alarm', 'monitoring_chart', 'alarm_chart'];
  if (!validDomains.includes(output.domain)) {
    return getErrorOutput();
  }

  // 辅助函数：将 null/undefined 转换为空字符串（仅用于字符串字段）
  const toStr = (val) => (val === null || val === undefined) ? '' : val;

  // 数据类型描述映射
  const dataEnumMap = {
    'real': '实时',
    'minute': '分钟',
    'hour': '小时',
    'day': '日'
  };

  // 获取 dataEnum，如果为空或无效则使用 'hour'
  let dataEnum = toStr(output.dataEnum);
  if (!dataEnum || !dataEnumMap[dataEnum]) {
    dataEnum = 'hour';
  }

  return {
    startTime: toStr(output.startTime),
    endTime: toStr(output.endTime),
    dataEnum: dataEnum,
    dataEnumDesc: dataEnumMap[dataEnum] || '小时',
    domain: toStr(output.domain),
    entName: toStr(output.entName),
    outPutName: toStr(output.outPutName),
    alarmType: output.alarmType ?? null,
    alarmStatus: output.alarmStatus ?? null,
    dealStatus: output.dealStatus ?? null,
    outPutType: output.outPutType ?? null
  };
}
